+/// Replicate each recipe in the plan VF times. This is used to implement
+/// whole-vector operations using scalar instructions.
+void VPlanTransforms::replicateByVF(VPlan &Plan, ElementCount VF) {
+  // TODO: Support replicating predicated plans.
+  if (Plan.isPredicated())
+    return;
+
+  // TODO: Support replicating plans with VPInstructions.
+  if (any_of(Plan.blocks(), [](const VPBlockBase *VPB) {
+        return !isa<VPBasicBlock>(VPB) ||
+               any_of(VPB->asVPBasicBlock()->recipes(),
+                      [](const VPRecipeBase &R) {
+                        return isa<VPInstruction>(&R) &&
+                               !isa<VPBranchOnMaskRecipe>(&R);
+                      });
+      }))
+    return;
+
+  VPBuilder Builder(Plan.getEntry()->getEntryBasicBlock()->getFirstNonPHI());
+  Type *IdxTy = Plan.getVectorTripCount()->getType();
+  DenseMap<VPRecipeBase *, SmallVector<VPValue *, 1>> Def2LaneDefs;
+  VPReplicator Replicator(Plan, Builder, IdxTy, Def2LaneDefs);
+
+  // Collect all recipes to be replicated.
+  SmallVector<VPRecipeBase *, 16> ToRemove;
+  for (VPBlockBase *VPB : Plan.blocks()) {
+    VPBasicBlock *VPBB = VPB->asVPBasicBlock();
+    for (VPRecipeBase &R : VPBB->recipes()) {
+      auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
+      if (!RepR)
+        continue;
+
+      // First-order recurrences are already replicated by the VPlan construction
+      // and are represented as a sequence of VPInstructions. We only need to
+      // handle uniform and non-uniform recipes here.
+      assert(RepR->isUniform() || !RepR->hasLaneDefs() ||
+             all_of(RepR->operands(),
+                    [&](VPValue *V) { return !isa<VPInstruction>(V->getDef()); }));
+
+      if (RepR->isUniform()) {
+        VPValue *V = RepR->getOperand(0);
+        for (VPValue *Def : RepR->definedValues()) {
+          // Replace all uses of the definition with the uniform operand.
+          for (VPUser &U : Def->users()) {
+            VPRecipeBase *User = &U;
+            for (unsigned I = 0, E = User->getNumOperands(); I != E; ++I)
+              if (User->getOperand(I) == Def)
+                User->setOperand(I, V);
+          }
+
+          // All uses of Def have been replaced by V, so we can remove Def.
+          RepR->removeDefinedValue(Def);
+        }
+
+        // If we removed all defined values, we can erase the recipe.
+        if (RepR->definedValues().empty())
+          ToRemove.push_back(RepR);
+        continue;
+      }
+
+      // Replicate the recipe for each lane.
+      Replicator.cloneForLane(RepR, VPLane(0, VF));
+      SmallVector<VPValue *, 1> &LaneDefs = Def2LaneDefs[RepR];
+
       /// Users that only demand the first lane can use the definition for lane
       /// 0.
       RepR->replaceUsesWithIf(LaneDefs[0], [RepR](VPUser &U, unsigned) {
